import React, { useState, useEffect, useRef, useCallback } from 'react';
import TopBar from './components/TopBar.jsx';
import DataPanel from './components/DataPanel.jsx';
import FeaturePanel from './components/FeaturePanel.jsx';
import NetworkVisualization from './components/NetworkVisualization.jsx';
import OutputPanel from './components/OutputPanel.jsx';
import HelpModal from './components/HelpModal.jsx';
import { datasets } from './utils/datasets.js';
import { applyFeatures } from './utils/features.js';
import { NeuralNetwork } from './utils/neuralNetwork.js';

function NeuralNetworkPlayground() {
  const [tailwindLoaded, setTailwindLoaded] = useState(false);
  const [darkMode, setDarkMode] = useState(false);

  // Central State Management
  const [state, setState] = useState({
    isPlaying: false,
    epoch: 0,
    learningRate: 0.03,
    activation: 'tanh',
    regularization: 'None',
    regularizationRate: 0,
    dataset: 'circle',
    noise: 0,
    trainTestRatio: 0.5,
    batchSize: 10,
    hiddenLayers: [4],
    enabledFeatures: {
      x1: true,
      x2: true,
      x1_squared: true,
      x2_squared: true,
      x1_x2: false,
      sin_x1: false,
      sin_x2: false
    },
    showTestData: false,
    discretizeOutput: false
  });

  // Data
  const [rawData, setRawData] = useState([]);
  const [trainData, setTrainData] = useState([]);
  const [testData, setTestData] = useState([]);

  // Network
  const [network, setNetwork] = useState(null);

  // Metrics
  const [trainLoss, setTrainLoss] = useState(0);
  const [testLoss, setTestLoss] = useState(0);
  const [lossHistory, setLossHistory] = useState({ train: [], test: [] });

  // Refs for training loop
  const animationRef = useRef(null);
  const lastUpdateRef = useRef(0);
  const batchIndexRef = useRef(0);
  const epochRef = useRef(0);

  // Force component updates for visualization
  const [visualUpdateTrigger, setVisualUpdateTrigger] = useState(0);

  // Help modal state
  const [showHelp, setShowHelp] = useState(false);

  // Hover state for visualization
  const [hoveredNode, setHoveredNode] = useState(null);

  // Load Tailwind and D3
  useEffect(() => {
    if (!document.getElementById('tailwind-script')) {
      const tailwindScript = document.createElement('script');
      tailwindScript.id = 'tailwind-script';
      tailwindScript.src = 'https://cdn.tailwindcss.com';
      tailwindScript.onload = () => {
        setTimeout(() => setTailwindLoaded(true), 100);
      };
      document.head.appendChild(tailwindScript);
    } else {
      setTailwindLoaded(true);
    }

    // Load D3
    if (!document.getElementById('d3-script')) {
      const d3Script = document.createElement('script');
      d3Script.id = 'd3-script';
      d3Script.src = 'https://d3js.org/d3.v7.min.js';
      document.head.appendChild(d3Script);
    }

    document.body.style.background = darkMode ? '#0f172a' : '#ffffff';
    document.documentElement.style.minHeight = '100%';
    return () => {
      document.body.style.background = '';
      document.documentElement.style.minHeight = '';
    };
  }, [darkMode]);

  // Generate initial data
  useEffect(() => {
    generateData();
  }, []);

  // Process raw data into train/test with features
  useEffect(() => {
    if (rawData.length === 0) return;

    const inputCount = Object.values(state.enabledFeatures).filter(Boolean).length;
    if (inputCount === 0) return;

    // Shuffle and split based on trainTestRatio
    const shuffled = [...rawData].sort(() => Math.random() - 0.5);
    const splitIndex = Math.floor(shuffled.length * state.trainTestRatio);

    const train = shuffled.slice(0, splitIndex).map(point => ({
      input: applyFeatures(point, state.enabledFeatures),
      label: point.label,
      x: point.x,
      y: point.y
    }));

    const test = shuffled.slice(splitIndex).map(point => ({
      input: applyFeatures(point, state.enabledFeatures),
      label: point.label,
      x: point.x,
      y: point.y
    }));

    setTrainData(train);
    setTestData(test);
  }, [rawData, state.enabledFeatures, state.trainTestRatio]);

  // Regenerate network when architecture, activation, or learning rate changes
  useEffect(() => {
    const inputCount = Object.values(state.enabledFeatures).filter(Boolean).length;
    if (inputCount > 0) {
      const layerSizes = [inputCount, ...state.hiddenLayers, 1];
      const newNetwork = new NeuralNetwork(layerSizes, state.activation, state.learningRate);
      setNetwork(newNetwork);

      // Reset metrics
      setState(prev => ({ ...prev, epoch: 0 }));
      setTrainLoss(0);
      setTestLoss(0);
      setLossHistory({ train: [], test: [] });
      batchIndexRef.current = 0;
      epochRef.current = 0;
    }
  }, [state.hiddenLayers, state.activation, state.enabledFeatures, state.learningRate]);

  // Training loop using requestAnimationFrame
  useEffect(() => {
    if (!state.isPlaying || !network || trainData.length === 0) {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
        animationRef.current = null;
      }
      return;
    }

    // Initialize epoch ref from state when training starts
    epochRef.current = state.epoch;

    const trainLoop = (timestamp) => {
      // Train at approximately 120 FPS (faster updates)
      if (timestamp - lastUpdateRef.current < 8) {
        animationRef.current = requestAnimationFrame(trainLoop);
        return;
      }

      lastUpdateRef.current = timestamp;

      // Create mini-batch using configured batch size
      const batch = [];

      for (let i = 0; i < state.batchSize && trainData.length > 0; i++) {
        batch.push(trainData[batchIndexRef.current % trainData.length]);
        batchIndexRef.current++;
      }

      // Train on batch with regularization
      const result = network.trainBatch(batch, state.regularization, state.regularizationRate);

      // Check for explosion
      if (result.exploded || network.hasExploded()) {
        console.warn('Network exploded! Resetting...');
        handleReset();
        return;
      }

      // Update train loss
      setTrainLoss(result.loss);

      // Calculate test loss every 10 epochs
      if (epochRef.current % 10 === 0 && testData.length > 0) {
        let totalTestLoss = 0;
        for (const sample of testData) {
          const pred = network.predict(sample.input);
          const error = pred - sample.label;
          totalTestLoss += error * error;
        }
        const avgTestLoss = totalTestLoss / testData.length;
        setTestLoss(avgTestLoss);

        // Update history
        setLossHistory(prev => ({
          train: [...prev.train.slice(-99), result.loss],
          test: [...prev.test.slice(-99), avgTestLoss]
        }));
      }

      // Increment epoch using ref for performance (avoid effect restart every epoch)
      epochRef.current++;
      setState(prev => ({ ...prev, epoch: epochRef.current }));

      // Force UI update every epoch for truly live updates
      setVisualUpdateTrigger(prev => prev + 1);

      // Continue loop
      animationRef.current = requestAnimationFrame(trainLoop);
    };

    animationRef.current = requestAnimationFrame(trainLoop);

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [state.isPlaying, network, trainData, testData, state.regularization, state.regularizationRate, state.batchSize]);

  const generateData = useCallback(() => {
    const generator = datasets[state.dataset];
    const points = generator(200, state.noise / 30);
    setRawData(points);
  }, [state.dataset, state.noise]);

  const handleReset = () => {
    // 1. Pause simulation if running and reset epoch
    setState(prev => ({ ...prev, isPlaying: false, epoch: 0 }));

    // 2. Clear loss history completely - graph will be blank
    setLossHistory({ train: [], test: [] });
    setTrainLoss(0);
    setTestLoss(0);

    // 3. Reset batch index and epoch ref
    batchIndexRef.current = 0;
    epochRef.current = 0;

    // 4. Create new network with fresh random weights
    const inputCount = Object.values(state.enabledFeatures).filter(Boolean).length;
    if (inputCount > 0) {
      const layerSizes = [inputCount, ...state.hiddenLayers, 1];
      const newNetwork = new NeuralNetwork(layerSizes, state.activation, state.learningRate);
      setNetwork(newNetwork);
    }

    // 5. Trigger visual update
    setVisualUpdateTrigger(prev => prev + 1);
  };

  const handleAddLayer = () => {
    if (state.hiddenLayers.length < 4) {
      setState(prev => ({
        ...prev,
        isPlaying: false,
        hiddenLayers: [...prev.hiddenLayers, 2]
      }));
    }
  };

  const handleRemoveLayer = () => {
    if (state.hiddenLayers.length > 0) {
      setState(prev => ({
        ...prev,
        isPlaying: false,
        hiddenLayers: prev.hiddenLayers.slice(0, -1)
      }));
    }
  };

  const handleAddNeuron = (layerIndex) => {
    if (state.hiddenLayers[layerIndex] < 8) {
      const newLayers = [...state.hiddenLayers];
      newLayers[layerIndex]++;
      setState(prev => ({
        ...prev,
        isPlaying: false,
        hiddenLayers: newLayers
      }));
    }
  };

  const handleRemoveNeuron = (layerIndex) => {
    if (state.hiddenLayers[layerIndex] > 1) {
      const newLayers = [...state.hiddenLayers];
      newLayers[layerIndex]--;
      setState(prev => ({
        ...prev,
        isPlaying: false,
        hiddenLayers: newLayers
      }));
    }
  };

  const handleToggleFeature = (featureKey) => {
    const newFeatures = {
      ...state.enabledFeatures,
      [featureKey]: !state.enabledFeatures[featureKey]
    };

    // Ensure at least one feature is enabled
    if (Object.values(newFeatures).some(Boolean)) {
      setState(prev => ({
        ...prev,
        isPlaying: false,
        enabledFeatures: newFeatures
      }));
    }
  };

  const handleDatasetChange = (ds) => {
    // Stop training
    setState(prev => ({ ...prev, dataset: ds, isPlaying: false, epoch: 0 }));

    // Clear loss history immediately
    setLossHistory({ train: [], test: [] });
    setTrainLoss(0);
    setTestLoss(0);

    // Reset epoch ref
    epochRef.current = 0;
    batchIndexRef.current = 0;

    // Generate new data
    setTimeout(() => {
      const generator = datasets[ds];
      const points = generator(200, state.noise / 30);
      setRawData(points);

      // After data is set, reset the network
      setTimeout(() => {
        const inputCount = Object.values(state.enabledFeatures).filter(Boolean).length;
        if (inputCount > 0) {
          const layerSizes = [inputCount, ...state.hiddenLayers, 1];
          const newNetwork = new NeuralNetwork(layerSizes, state.activation, state.learningRate);
          setNetwork(newNetwork);

          // Trigger visual update
          setVisualUpdateTrigger(prev => prev + 1);
        }
      }, 100);
    }, 0);
  };

  const handleRegenerate = () => {
    setState(prev => ({ ...prev, isPlaying: false }));
    generateData();
    handleReset();
  };

  if (!tailwindLoaded) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif',
        color: '#9ca3af'
      }}>
        Loading Neural Network Playground...
      </div>
    );
  }

  const inputCount = Object.values(state.enabledFeatures).filter(Boolean).length;

  return (
    <div 
      className="min-h-screen"
      style={{ 
        fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif'
      }}
    >
      {/* Top Bar */}
      <TopBar
        isPlaying={state.isPlaying}
        onTogglePlay={() => setState(prev => ({ ...prev, isPlaying: !prev.isPlaying }))}
        onReset={handleReset}
        learningRate={state.learningRate}
        onLearningRateChange={(lr) => {
          setState(prev => ({ ...prev, learningRate: lr, isPlaying: false }));
        }}
        activation={state.activation}
        onActivationChange={(act) => {
          setState(prev => ({ ...prev, activation: act, isPlaying: false }));
        }}
        regularization={state.regularization}
        onRegularizationChange={(reg) => {
          setState(prev => ({ ...prev, regularization: reg }));
        }}
        regularizationRate={state.regularizationRate}
        onRegularizationRateChange={(rate) => {
          setState(prev => ({ ...prev, regularizationRate: rate }));
        }}
        onShowHelp={() => setShowHelp(true)}
        darkMode={darkMode}
        onToggleDarkMode={() => setDarkMode(prev => !prev)}
      />

      {/* Main Content - Column Layout */}
      <div className="p-6">
        <div className="flex gap-4 items-stretch" style={{ minWidth: 0 }}>
          {/* 1. Data */}
          <DataPanel
            dataset={state.dataset}
            onDatasetChange={handleDatasetChange}
            noise={state.noise}
            onNoiseChange={(n) => setState(prev => ({ ...prev, noise: n }))}
            trainTestRatio={state.trainTestRatio}
            onTrainTestRatioChange={(ratio) => setState(prev => ({ ...prev, trainTestRatio: ratio }))}
            batchSize={state.batchSize}
            onBatchSizeChange={(size) => setState(prev => ({ ...prev, batchSize: size }))}
            onRegenerate={handleRegenerate}
            darkMode={darkMode}
          />

          {/* 2. Features & Network - Unified Card */}
          <div className="flex-1 rounded-3xl p-6 flex flex-col" style={{ 
            minWidth: 0, 
            minHeight: '100%',
            backgroundColor: darkMode ? '#1e293b' : '#ffffff',
            border: darkMode ? '1px solid #334155' : '1px solid #f0f0f0'
          }}>
            <div className="mb-4">
              <h3 className="text-sm font-bold tracking-tight" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>
                2. Network Architecture
              </h3>
              <p className="text-xs mt-0.5 font-light" style={{ color: darkMode ? '#94a3b8' : '#6b7280' }}>
                <span className="text-indigo-400 font-medium">Blue</span> = Class 1, <span className="text-orange-400 font-medium">Orange</span> = Class 0
              </p>
            </div>

            <div className="flex gap-3 flex-grow" style={{ minWidth: 0, minHeight: 0 }}>
              <FeaturePanel
                enabledFeatures={state.enabledFeatures}
                onToggleFeature={handleToggleFeature}
                onHover={node => setHoveredNode(node)}
                darkMode={darkMode}
              />
              <NetworkVisualization
                hiddenLayers={state.hiddenLayers}
                onAddLayer={handleAddLayer}
                onRemoveLayer={handleRemoveLayer}
                onAddNeuron={handleAddNeuron}
                onRemoveNeuron={handleRemoveNeuron}
                inputCount={inputCount}
                network={network}
                visualUpdateTrigger={visualUpdateTrigger}
                onHover={node => setHoveredNode(node)}
                hoveredNode={hoveredNode}
                isPlaying={state.isPlaying}
                darkMode={darkMode}
              />
            </div>
          </div>

          {/* 4. Output */}
          <OutputPanel
            trainLoss={trainLoss}
            testLoss={testLoss}
            lossHistory={lossHistory}
            epoch={state.epoch}
            showTestData={state.showTestData}
            onToggleTestData={() => setState(prev => ({ ...prev, showTestData: !prev.showTestData }))}
            discretizeOutput={state.discretizeOutput}
            onToggleDiscretize={() => setState(prev => ({ ...prev, discretizeOutput: !prev.discretizeOutput }))}
            trainData={trainData}
            testData={testData}
            network={network}
            enabledFeatures={state.enabledFeatures}
            visualUpdateTrigger={visualUpdateTrigger}
            hoveredNode={hoveredNode}
            darkMode={darkMode}
          />
        </div>
      </div>

      {/* Help Modal */}
      <HelpModal isOpen={showHelp} onClose={() => setShowHelp(false)} darkMode={darkMode} />
    </div>
  );
}

export default NeuralNetworkPlayground;

sources.components/DataPanel.jsx:
import React from 'react';

function DataPanel({
  dataset,
  onDatasetChange,
  noise,
  onNoiseChange,
  trainTestRatio,
  onTrainTestRatioChange,
  batchSize,
  onBatchSizeChange,
  onRegenerate,
  darkMode
}) {
  const datasets = [
    { id: 'circle', name: 'Circle', description: 'Beginner: Separate the inner circle' },
    { id: 'xor', name: 'XOR', description: 'Intermediate: Separate diagonal corners' },
    { id: 'gaussian', name: 'Gaussian', description: 'Easy: Separate two distinct blobs' },
    { id: 'spiral', name: 'Spiral', description: 'Hard: Separate intertwined spirals' }
  ];

  // SVG Icons for datasets
  const icons = {
    circle: (
      <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
        <circle cx="12" cy="12" r="8" stroke="currentColor" strokeWidth="2" />
        <circle cx="12" cy="12" r="3" fill="currentColor" />
      </svg>
    ),
    xor: (
      <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
        <rect x="4" y="4" width="7" height="7" fill="currentColor" rx="1" />
        <rect x="13" y="13" width="7" height="7" fill="currentColor" rx="1" />
        <rect x="4" y="13" width="7" height="7" stroke="currentColor" strokeWidth="2" rx="1" />
        <rect x="13" y="4" width="7" height="7" stroke="currentColor" strokeWidth="2" rx="1" />
      </svg>
    ),
    gaussian: (
      <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
        <circle cx="8" cy="16" r="3" fill="currentColor" />
        <circle cx="16" cy="8" r="3" stroke="currentColor" strokeWidth="2" />
      </svg>
    ),
    spiral: (
      <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
        <path d="M12 12m-9 0a9 9 0 1 0 18 0a9 9 0 1 0 -18 0" stroke="currentColor" strokeWidth="2" strokeDasharray="4 2" />
        <path d="M12 12L16 16" stroke="currentColor" strokeWidth="2" />
      </svg>
    )
  };

  return (
    <div 
      className="rounded-3xl p-6 flex flex-col"
      style={{ 
        width: '250px',
        backgroundColor: darkMode ? '#1e293b' : '#ffffff',
        border: darkMode ? '1px solid #334155' : '1px solid #f0f0f0',
        flexShrink: 0
      }}
    >
      <div className="mb-4">
        <h3 className="text-sm font-bold tracking-tight" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>
          1. Choose Data
        </h3>
        <p className="text-xs mt-1 font-light" style={{ color: darkMode ? '#94a3b8' : '#6b7280' }}>
          What shape do you want to learn?
        </p>
      </div>

      {/* Dataset Picker */}
      <div className="mb-6">
        <div className="grid grid-cols-2 gap-3">
          {datasets.map(ds => (
            <button
              key={ds.id}
              onClick={() => onDatasetChange(ds.id)}
              className="w-full p-3 rounded-2xl text-left transition-all flex flex-col items-center justify-center gap-2 aspect-square group relative overflow-hidden"
              style={{
                backgroundColor: dataset === ds.id ? (darkMode ? '#312e81' : '#f5f7ff') : (darkMode ? '#0f172a' : '#ffffff'),
                color: dataset === ds.id ? (darkMode ? '#a5b4fc' : '#6366f1') : (darkMode ? '#64748b' : '#9ca3af'),
                border: dataset === ds.id ? (darkMode ? '2px solid #6366f1' : '2px solid #6366f1') : (darkMode ? '1px solid #334155' : '1px solid #f0f0f0'),
                boxShadow: dataset === ds.id ? '0 4px 12px rgba(99, 102, 241, 0.15)' : 'none'
              }}
              title={ds.description}
            >
              <div style={{ opacity: dataset === ds.id ? 1 : 0.7 }}>
                {icons[ds.id]}
              </div>
              <span className="text-xs font-medium">{ds.name}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Sliders */}
      <div className="space-y-5 flex-grow">
        <div>
          <div className="flex justify-between items-center mb-2">
            <div className="flex flex-col">
              <label className="text-xs font-medium" style={{ color: darkMode ? '#cbd5e1' : '#374151' }}>Noise</label>
              <span className="text-[10px]" style={{ color: darkMode ? '#64748b' : '#9ca3af' }}>Messiness of data</span>
            </div>
            <span className="text-xs font-bold px-2 py-1 rounded-md" style={{ 
              color: darkMode ? '#f1f5f9' : '#111827',
              backgroundColor: darkMode ? '#0f172a' : '#f3f4f6'
            }}>{noise}</span>
          </div>
          <input
            type="range"
            min="0"
            max="50"
            step="5"
            value={noise}
            onChange={(e) => onNoiseChange(parseInt(e.target.value))}
            className="w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            style={{ backgroundColor: darkMode ? '#334155' : '#f3f4f6' }}
          />
        </div>

        <div>
          <div className="flex justify-between items-center mb-2">
            <div className="flex flex-col">
              <label className="text-xs font-medium" style={{ color: darkMode ? '#cbd5e1' : '#374151' }}>Train/Test Split</label>
              <span className="text-[10px]" style={{ color: darkMode ? '#64748b' : '#9ca3af' }}>Data for learning vs checking</span>
            </div>
            <span className="text-xs font-bold px-2 py-1 rounded-md" style={{ 
              color: darkMode ? '#f1f5f9' : '#111827',
              backgroundColor: darkMode ? '#0f172a' : '#f3f4f6'
            }}>
              {Math.round(trainTestRatio * 100)}%
            </span>
          </div>
          <input
            type="range"
            min="0.1"
            max="0.9"
            step="0.1"
            value={trainTestRatio}
            onChange={(e) => onTrainTestRatioChange(parseFloat(e.target.value))}
            className="w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            style={{ backgroundColor: darkMode ? '#334155' : '#f3f4f6' }}
          />
        </div>

        <div>
          <div className="flex justify-between items-center mb-2">
            <div className="flex flex-col">
              <label className="text-xs font-medium" style={{ color: darkMode ? '#cbd5e1' : '#374151' }}>Batch Size</label>
              <span className="text-[10px]" style={{ color: darkMode ? '#64748b' : '#9ca3af' }}>Points processed at once</span>
            </div>
            <span className="text-xs font-bold px-2 py-1 rounded-md" style={{ 
              color: darkMode ? '#f1f5f9' : '#111827',
              backgroundColor: darkMode ? '#0f172a' : '#f3f4f6'
            }}>{batchSize}</span>
          </div>
          <input
            type="range"
            min="1"
            max="30"
            step="1"
            value={batchSize}
            onChange={(e) => onBatchSizeChange(parseInt(e.target.value))}
            className="w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            style={{ backgroundColor: darkMode ? '#334155' : '#f3f4f6' }}
          />
        </div>
      </div>

      {/* Regenerate Button */}
      <button
        onClick={onRegenerate}
        className="w-full mt-6 py-3 rounded-xl font-medium transition-all text-sm flex items-center justify-center gap-2"
        style={{
          color: darkMode ? '#a5b4fc' : '#6366f1',
          backgroundColor: darkMode ? '#1e1b4b' : '#eef2ff',
          border: darkMode ? '1px solid #312e81' : '1px solid #e0e7ff'
        }}
        onMouseEnter={(e) => e.currentTarget.style.backgroundColor = darkMode ? '#312e81' : '#ddd6fe'}
        onMouseLeave={(e) => e.currentTarget.style.backgroundColor = darkMode ? '#1e1b4b' : '#eef2ff'}
      >
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
        </svg>
        New Random Data
      </button>
    </div>
  );
}

export default DataPanel;

sources.components/FeaturePanel.jsx:
import React from 'react';
import { featureDefinitions } from '../utils/features.js';

function FeaturePanel({ enabledFeatures, onToggleFeature, onHover, darkMode }) {
  return (
    <div 
      className="flex flex-col gap-2"
      style={{ 
        width: '190px',
        flexShrink: 0
      }}
    >
      <div className="mb-1 px-1">
        <h4 className="text-[10px] font-bold uppercase tracking-wider" style={{ color: darkMode ? '#e2e8f0' : '#111827' }}>
          Features
        </h4>
      </div>

      <div className="space-y-2">
        {featureDefinitions.map(feature => (
          <button
            key={feature.key}
            onClick={() => onToggleFeature(feature.key)}
            onMouseEnter={() => onHover && onHover({ type: 'feature', id: feature.key })}
            onMouseLeave={() => onHover && onHover(null)}
            className="w-full px-3.5 py-3 rounded-xl text-left transition-all flex items-center gap-3"
            style={{
              backgroundColor: darkMode ? '#0f172a' : '#ffffff',
              border: enabledFeatures[feature.key] ? (darkMode ? '1px solid #6366f1' : '1px solid #6366f1') : (darkMode ? '1px solid #334155' : '1px solid #e5e7eb'),
              boxShadow: enabledFeatures[feature.key] ? '0 3px 8px rgba(99, 102, 241, 0.15)' : 'none',
              opacity: enabledFeatures[feature.key] ? 1 : 0.6
            }}
          >
            <div 
              className="w-5 h-5 rounded flex items-center justify-center flex-shrink-0 transition-colors"
              style={{
                backgroundColor: enabledFeatures[feature.key] ? '#6366f1' : (darkMode ? '#334155' : '#f3f4f6'),
              }}
            >
              {enabledFeatures[feature.key] && (
                <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              )}
            </div>

            <div className="flex-1 min-w-0">
              <div className="text-sm font-semibold leading-tight" style={{ 
                color: enabledFeatures[feature.key] ? (darkMode ? '#f1f5f9' : '#111827') : (darkMode ? '#64748b' : '#6b7280')
              }}>
                {feature.label}
              </div>
              <div className="text-[10px] leading-tight mt-1" style={{ color: darkMode ? '#64748b' : '#9ca3af' }}>
                {getFeatureDescription(feature.key)}
              </div>
            </div>
          </button>
        ))}
      </div>
    </div>
  );
}

function getFeatureDescription(key) {
  switch(key) {
    case 'x1': return 'Horizontal position';
    case 'x2': return 'Vertical position';
    case 'x1_squared': return 'Distance from vertical center';
    case 'x2_squared': return 'Distance from horizontal center';
    case 'x1_x2': return 'Diagonal interaction';
    case 'sin_x1': return 'Wavy horizontal pattern';
    case 'sin_x2': return 'Wavy vertical pattern';
    default: return 'Input value';
  }
}

export default FeaturePanel;

sources.components/HelpModal.jsx:
import React from 'react';

function HelpModal({ isOpen, onClose, darkMode }) {
  if (!isOpen) return null;

  return (
    <div 
      className="fixed inset-0 flex items-center justify-center z-[100]"
      style={{ 
        backgroundColor: darkMode ? 'rgba(15, 23, 42, 0.9)' : 'rgba(255, 255, 255, 0.9)',
        backdropFilter: 'blur(8px)' 
      }}
      onClick={onClose}
    >
      <div 
        className="rounded-3xl max-w-4xl max-h-[90vh] overflow-y-auto"
        style={{ 
          boxShadow: darkMode ? '0 25px 60px rgba(0, 0, 0, 0.5)' : '0 25px 60px rgba(0, 0, 0, 0.08)',
          width: '90%',
          backgroundColor: darkMode ? '#1e293b' : '#ffffff',
          border: darkMode ? '1px solid #334155' : '1px solid #f0f0f0'
        }}
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="sticky top-0 backdrop-blur-sm px-10 py-8 flex items-center justify-between z-10" style={{ 
          backgroundColor: darkMode ? 'rgba(30, 41, 59, 0.95)' : 'rgba(255, 255, 255, 0.95)',
          borderBottom: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
        }}>
          <div>
            <h2 className="text-3xl font-bold tracking-tight" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>
              Neural Network Playground
            </h2>
            <p className="font-light mt-1 text-lg" style={{ color: darkMode ? '#94a3b8' : '#6b7280' }}>
              Learn by experimenting.
            </p>
          </div>
          <button
            onClick={onClose}
            className="w-10 h-10 rounded-full flex items-center justify-center transition-colors"
            style={{ 
              color: darkMode ? '#94a3b8' : '#9ca3af'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = darkMode ? '#334155' : '#f9fafb';
              e.currentTarget.style.color = darkMode ? '#e2e8f0' : '#374151';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = 'transparent';
              e.currentTarget.style.color = darkMode ? '#94a3b8' : '#9ca3af';
            }}
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Content */}
        <div className="px-10 py-10 space-y-16">

          {/* Main Intro */}
          <section className="space-y-6">
            <h3 className="text-2xl font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Quick Start</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="space-y-3">
                <div className="w-10 h-10 rounded-xl flex items-center justify-center font-bold text-lg" style={{ 
                  backgroundColor: darkMode ? '#312e81' : '#eef2ff',
                  color: darkMode ? '#a5b4fc' : '#6366f1'
                }}>1</div>
                <h4 className="font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Pick a Dataset</h4>
                <p className="leading-relaxed text-sm" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                  Choose a shape on the left (like Circles or Spirals). This creates a pattern of blue and orange dots.
                </p>
              </div>
              <div className="space-y-3">
                <div className="w-10 h-10 rounded-xl flex items-center justify-center font-bold text-lg" style={{ 
                  backgroundColor: darkMode ? '#312e81' : '#eef2ff',
                  color: darkMode ? '#a5b4fc' : '#6366f1'
                }}>2</div>
                <h4 className="font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Design the Brain</h4>
                <p className="leading-relaxed text-sm" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                  Toggle features and adjust layers. More complexity helps with harder patterns but trains slower.
                </p>
              </div>
              <div className="space-y-3">
                <div className="w-10 h-10 rounded-xl flex items-center justify-center font-bold text-lg" style={{ 
                  backgroundColor: darkMode ? '#312e81' : '#eef2ff',
                  color: darkMode ? '#a5b4fc' : '#6366f1'
                }}>3</div>
                <h4 className="font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Press Train</h4>
                <p className="leading-relaxed text-sm" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                  Watch the network learn in real-time. The background colors show where it thinks each dot type belongs.
                </p>
              </div>
            </div>
          </section>

          <hr style={{ borderColor: darkMode ? '#334155' : '#e5e7eb' }} />

          {/* Concept Explanation */}
          <section className="space-y-6">
            <h3 className="text-2xl font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Understanding the Map</h3>
            <div className="rounded-3xl p-8 space-y-6" style={{ backgroundColor: darkMode ? '#0f172a' : 'rgba(249, 250, 251, 0.5)' }}>
              <p className="leading-relaxed text-base" style={{ color: darkMode ? '#cbd5e1' : '#374151' }}>
                The network is learning to classify points. It paints a map showing where it expects to find blue dots versus orange dots.
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="p-6 rounded-2xl shadow-sm" style={{ 
                  backgroundColor: darkMode ? '#1e293b' : '#ffffff',
                  border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
                }}>
                  <h4 className="font-bold mb-2 flex items-center gap-2" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>
                    <span className="w-4 h-4 rounded-full bg-indigo-500"></span>
                    Blue Region
                  </h4>
                  <p className="text-sm leading-relaxed" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                    The network is confident this area contains blue dots. The darker the blue, the more confident it is.
                  </p>
                </div>
                <div className="p-6 rounded-2xl shadow-sm" style={{ 
                  backgroundColor: darkMode ? '#1e293b' : '#ffffff',
                  border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
                }}>
                  <h4 className="font-bold mb-2 flex items-center gap-2" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>
                    <span className="w-4 h-4 rounded-full bg-orange-500"></span>
                    Orange Region
                  </h4>
                  <p className="text-sm leading-relaxed" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                    The network is confident this area contains orange dots. The darker the orange, the more confident.
                  </p>
                </div>
              </div>

              <p className="text-sm italic" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                {darkMode ? 'Dark' : 'White or light'} areas = the network isn't sure yet. This is normal at the start!
              </p>
            </div>
          </section>

          <hr style={{ borderColor: darkMode ? '#334155' : '#e5e7eb' }} />

          {/* Interactive Features */}
          <section className="space-y-6">
            <h3 className="text-2xl font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Pro Tip: Hover to Explore</h3>
            <div className="rounded-3xl p-8" style={{ backgroundColor: darkMode ? 'rgba(49, 46, 129, 0.2)' : 'rgba(238, 242, 255, 0.5)' }}>
              <p className="leading-relaxed text-base mb-4" style={{ color: darkMode ? '#cbd5e1' : '#374151' }}>
                Try hovering over the features and neurons! The map will change to show what that specific component "sees".
              </p>
              <ul className="space-y-3 text-sm" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                <li className="flex gap-3">
                  <span className="font-bold" style={{ color: darkMode ? '#a5b4fc' : '#6366f1' }}>→</span>
                  <span><strong style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Hover a feature:</strong> See how that input (like X₁²) varies across space</span>
                </li>
                <li className="flex gap-3">
                  <span className="font-bold" style={{ color: darkMode ? '#a5b4fc' : '#6366f1' }}>→</span>
                  <span><strong style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Hover a neuron:</strong> See what pattern that specific neuron is detecting</span>
                </li>
              </ul>
            </div>
          </section>

          <hr style={{ borderColor: darkMode ? '#334155' : '#e5e7eb' }} />

          {/* Challenges */}
          <section className="space-y-6">
            <h3 className="text-2xl font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Fun Challenges</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="group rounded-2xl p-6 hover:shadow-md transition-all cursor-default" style={{ 
                border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
              }}>
                <h4 className="font-bold mb-2 transition-colors" style={{ 
                  color: darkMode ? '#f1f5f9' : '#111827'
                }}>The No-Hidden-Layer Challenge</h4>
                <p className="text-sm mb-3" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>Can you solve the Circle dataset without any hidden layers?</p>
                <div className="text-xs inline-block px-3 py-1.5 rounded-lg" style={{ 
                  color: darkMode ? '#94a3b8' : '#4b5563',
                  backgroundColor: darkMode ? '#0f172a' : '#ffffff',
                  border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
                }}>Hint: Enable X₁² and X₂² features</div>
              </div>

              <div className="group rounded-2xl p-6 hover:shadow-md transition-all cursor-default" style={{ 
                border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
              }}>
                <h4 className="font-bold mb-2 transition-colors" style={{ 
                  color: darkMode ? '#f1f5f9' : '#111827'
                }}>XOR with Minimal Neurons</h4>
                <p className="text-sm mb-3" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>Solve the XOR pattern using the fewest neurons possible.</p>
                <div className="text-xs inline-block px-3 py-1.5 rounded-lg" style={{ 
                  color: darkMode ? '#94a3b8' : '#4b5563',
                  backgroundColor: darkMode ? '#0f172a' : '#ffffff',
                  border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
                }}>Hint: Try X₁X₂ feature or 1 layer with 2-4 neurons</div>
              </div>

              <div className="group rounded-2xl p-6 hover:shadow-md transition-all cursor-default" style={{ 
                border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
              }}>
                <h4 className="font-bold mb-2 transition-colors" style={{ 
                  color: darkMode ? '#f1f5f9' : '#111827'
                }}>The Spiral Master</h4>
                <p className="text-sm mb-3" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>This is the hardest pattern. Be patient!</p>
                <div className="text-xs inline-block px-3 py-1.5 rounded-lg" style={{ 
                  color: darkMode ? '#94a3b8' : '#4b5563',
                  backgroundColor: darkMode ? '#0f172a' : '#ffffff',
                  border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
                }}>Hint: Use sin(X₁) and sin(X₂), wait 500+ steps</div>
              </div>

              <div className="group rounded-2xl p-6 hover:shadow-md transition-all cursor-default" style={{ 
                border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
              }}>
                <h4 className="font-bold mb-2 transition-colors" style={{ 
                  color: darkMode ? '#f1f5f9' : '#111827'
                }}>Spot the Overfit</h4>
                <p className="text-sm mb-3" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>Watch what happens when you make the network too complex for a simple problem.</p>
                <div className="text-xs inline-block px-3 py-1.5 rounded-lg" style={{ 
                  color: darkMode ? '#94a3b8' : '#4b5563',
                  backgroundColor: darkMode ? '#0f172a' : '#ffffff',
                  border: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
                }}>Try: Gaussian dataset with 3 layers of 8 neurons each</div>
              </div>
            </div>
          </section>

          <hr style={{ borderColor: darkMode ? '#334155' : '#e5e7eb' }} />

          {/* Understanding Overfitting */}
          <section className="space-y-6">
            <h3 className="text-2xl font-bold" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>What is Overfitting?</h3>
            <div className="rounded-3xl p-8 space-y-4" style={{ backgroundColor: darkMode ? 'rgba(124, 45, 18, 0.15)' : 'rgba(255, 247, 237, 0.5)' }}>
              <p className="leading-relaxed text-base" style={{ color: darkMode ? '#cbd5e1' : '#374151' }}>
                Overfitting happens when your network memorizes the training dots instead of learning the actual pattern.
              </p>
              <div className="rounded-2xl p-6" style={{ 
                backgroundColor: darkMode ? '#1e293b' : '#ffffff',
                border: darkMode ? '1px solid #7c2d12' : '1px solid #fed7aa'
              }}>
                <h4 className="font-bold mb-3" style={{ color: darkMode ? '#f1f5f9' : '#111827' }}>Signs you're overfitting:</h4>
                <ul className="space-y-2 text-sm" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                  <li className="flex gap-2">
                    <span className="font-bold" style={{ color: darkMode ? '#fb923c' : '#f97316' }}>•</span>
                    <span>Train Loss keeps going down, but Test Loss starts going UP</span>
                  </li>
                  <li className="flex gap-2">
                    <span className="font-bold" style={{ color: darkMode ? '#fb923c' : '#f97316' }}>•</span>
                    <span>The decision boundary looks weirdly squiggly around individual dots</span>
                  </li>
                  <li className="flex gap-2">
                    <span className="font-bold" style={{ color: darkMode ? '#fb923c' : '#f97316' }}>•</span>
                    <span>You have way more neurons than you need for the pattern</span>
                  </li>
                </ul>
              </div>
              <p className="text-sm italic" style={{ color: darkMode ? '#94a3b8' : '#4b5563' }}>
                Fix it by: reducing layers/neurons, adding regularization (L2), or getting more training data.
              </p>
            </div>
          </section>

        </div>

        {/* Footer */}
        <div className="sticky bottom-0 backdrop-blur-sm px-10 py-6 flex justify-end z-10" style={{ 
          backgroundColor: darkMode ? 'rgba(30, 41, 59, 0.95)' : 'rgba(255, 255, 255, 0.95)',
          borderTop: darkMode ? '1px solid #334155' : '1px solid #e5e7eb'
        }}>
          <button
            onClick={onClose}
            className="px-8 py-3 rounded-xl font-medium text-white transition-all hover:opacity-90 active:scale-95 shadow-lg"
            style={{ 
              backgroundColor: '#6366f1',
              boxShadow: darkMode ? '0 10px 25px rgba(99, 102, 241, 0.3)' : '0 10px 25px rgba(165, 180, 252, 0.4)'
            }}
          >
            Got it, let's go!
          </button>
        </div>
      </div>
    </div>
  );
}

export default HelpModal;

